    if mode != "self_PINotSetMakeCredAndWithoutPinAuthParamEnumerateCredential" and mode != "self_PINotSetMakeCredAndWithRkAlwaysUvFalse":
        pinUvAuthParam = hmac.new(pinToken, message, digestmod='sha256').digest()[:32]
